import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    out = np.zeros_like(grid)
    rows, cols = grid.shape

    colors = [c for c in np.unique(grid) if c != 0]
    for color in colors:
        coords = np.argwhere(grid == color)
        if coords.size == 0:
            continue
        min_r = coords[:, 0].min()
        max_r = coords[:, 0].max()

        for r in range(min_r, max_r + 1):
            cols_r = np.where(grid[r] == color)[0]
            if cols_r.size == 0:
                continue
            if r == max_r:
                out[r, cols_r] = color
            else:
                out[r, cols_r + 1] = color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid, return_counts=True)
    nonzero = vals[vals != 0]
    if len(nonzero) == 0:
        return grid.copy()
    color_counts = {v: counts[vals == v][0] for v in nonzero}
    target = min(color_counts, key=lambda c: color_counts[c])
    positions = np.argwhere(grid == target)
    r0, c0 = positions.min(axis=0)
    r1, c1 = positions.max(axis=0) + 1
    return grid[r0:r1, c0:c1].copy()

