def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    for r in range(h):
        row = grid[r]
        nonzero = np.where(row != 0)[0]
        if nonzero.size >= 2:
            left = nonzero[0]
            right = nonzero[-1]
            if row[left] == row[right] and row[left] != 0:
                grid[r, left:right + 1] = row[left]
    return grid

