def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    h, w = grid.shape

    # Find the two 2x2 red blocks (color 2)
    red_blocks = []
    for r in range(h - 1):
        for c in range(w - 1):
            if np.all(grid[r:r+2, c:c+2] == 2):
                red_blocks.append((r, c))
    red_blocks = list(dict.fromkeys(red_blocks))
    if len(red_blocks) < 2:
        return np.array([[0]], dtype=int)

    # Use the first two distinct 2x2 red blocks
    (r1, c1), (r2, c2) = red_blocks[0], red_blocks[1]

    teal = (grid == 8)
    visited = np.zeros_like(teal, dtype=bool)

    # 4-neighborhood
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    def touches_block(component_cells, block):
        br, bc = block
        for r, c in component_cells:
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if br <= nr <= br + 1 and bc <= nc <= bc + 1:
                    return True
        return False

    for sr in range(h):
        for sc in range(w):
            if teal[sr, sc] and not visited[sr, sc]:
                stack = [(sr, sc)]
                visited[sr, sc] = True
                component = []
                while stack:
                    r, c = stack.pop()
                    component.append((r, c))
                    for dr, dc in dirs:
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < h and 0 <= nc < w and teal[nr, nc] and not visited[nr, nc]:
                            visited[nr, nc] = True
                            stack.append((nr, nc))

                if touches_block(component, (r1, c1)) and touches_block(component, (r2, c2)):
                    return np.array([[8]], dtype=int)

    return np.array([[0]], dtype=int)

