def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    pts = np.argwhere(grid == 8)

    # Draw horizontal lines between teal cells in the same row
    for r in range(h):
        cols = np.where(grid[r] == 8)[0]
        if len(cols) >= 2:
            c1, c2 = cols.min(), cols.max()
            if c2 - c1 > 1:
                grid[r, c1 + 1:c2] = 3

    # Draw vertical lines between teal cells in the same column
    for c in range(w):
        rows = np.where(grid[:, c] == 8)[0]
        if len(rows) >= 2:
            r1, r2 = rows.min(), rows.max()
            if r2 - r1 > 1:
                grid[r1 + 1:r2, c] = 3

    return grid

