import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    colors = [c for c in np.unique(grid) if c != 0]
    if len(colors) < 2:
        return grid

    # Identify separator color as the one forming full rows/cols most consistently.
    best_sep = None
    best_score = -1
    for c in colors:
        row_score = sum(np.all(grid[r, :] == c) for r in range(h))
        col_score = sum(np.all(grid[:, col] == c) for col in range(w))
        score = max(row_score, col_score)
        if score > best_score:
            best_score = score
            best_sep = c

    sep = best_sep
    non_sep_colors = [c for c in colors if c != sep]
    if len(non_sep_colors) < 2:
        return grid

    # Determine seed and fill colors by looking at non-separator connected components.
    # Seed color is the one with fewer total cells across components.
    counts = {}
    for c in non_sep_colors:
        counts[c] = int(np.sum(grid == c))
    sorted_colors = sorted(non_sep_colors, key=lambda c: counts[c])
    seed_color = sorted_colors[0]
    fill_color = sorted_colors[-1]

    # Find relative offsets of fill cells around seed cells within compartments.
    # Compartment boundaries are separator lines; use positions of seed cells and fill cells.
    seed_positions = np.argwhere(grid == seed_color)
    fill_positions = np.argwhere(grid == fill_color)

    if len(seed_positions) == 0 or len(fill_positions) == 0:
        return grid

    # Infer compartment step from separator lines.
    row_seps = [r for r in range(h) if np.all(grid[r, :] == sep)]
    col_seps = [c for c in range(w) if np.all(grid[:, c] == sep)]

    def step_from_seps(seps):
        if len(seps) >= 2:
            diffs = [seps[i + 1] - seps[i] for i in range(len(seps) - 1)]
            vals, cnts = np.unique(diffs, return_counts=True)
            return int(vals[np.argmax(cnts)])
        return None

    row_step = step_from_seps(row_seps)
    col_step = step_from_seps(col_seps)

    # Determine offsets by comparing all seed cells to fill cells in same compartment pattern.
    offsets = set()
    for sr, sc in seed_positions:
        for fr, fc in fill_positions:
            dr, dc = fr - sr, fc - sc
            # Only consider small local offsets within one compartment neighborhood.
            if abs(dr) <= 4 and abs(dc) <= 4 and not (dr == 0 and dc == 0):
                offsets.add((dr, dc))

    # If no offsets found, fall back to local 3x3 neighborhood around seed cells.
    if not offsets:
        offsets = set()
        for sr, sc in seed_positions:
            for dr in (-1, 0, 1):
                for dc in (-1, 0, 1):
                    if dr != 0 or dc != 0:
                        rr, cc = sr + dr, sc + dc
                        if 0 <= rr < h and 0 <= cc < w and grid[rr, cc] == fill_color:
                            offsets.add((dr, dc))

    # Apply learned offsets to every seed cell, filling only black cells.
    out = np.array(grid, copy=True)
    for sr, sc in seed_positions:
        for dr, dc in offsets:
            rr, cc = sr + dr, sc + dc
            if 0 <= rr < h and 0 <= cc < w and out[rr, cc] == 0:
                out[rr, cc] = fill_color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, dtype=int)
    h, w = grid.shape
    first = grid[0].copy()
    second = np.zeros(w, dtype=int)
    for j, val in enumerate(first):
        if val != 0:
            if j - 1 >= 0:
                second[j - 1] = val
            if j + 1 < w:
                second[j + 1] = val
    out = np.zeros_like(grid)
    for i in range(h):
        out[i] = first if i % 2 == 0 else second
    return out

