import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = grid.copy()

    # Find connected blue components (color 1)
    visited = np.zeros((h, w), dtype=bool)
    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    def bfs(sr, sc):
        stack = [(sr, sc)]
        visited[sr, sc] = True
        cells = []
        while stack:
            r, c = stack.pop()
            cells.append((r, c))
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if 0 <= nr < h and 0 <= nc < w and not visited[nr, nc] and grid[nr, nc] == 1:
                    visited[nr, nc] = True
                    stack.append((nr, nc))
        return cells

    components = []
    for r in range(h):
        for c in range(w):
            if grid[r, c] == 1 and not visited[r, c]:
                comp = bfs(r, c)
                components.append(comp)

    for comp in components:
        rows = [r for r, _ in comp]
        cols = [c for _, c in comp]
        rmin, rmax = min(rows), max(rows)
        cmin, cmax = min(cols), max(cols)

        # Find the single non-blue colored cell inside the container
        fill_color = None
        for r in range(rmin, rmax + 1):
            for c in range(cmin, cmax + 1):
                if grid[r, c] not in (0, 1):
                    fill_color = grid[r, c]
                    break
            if fill_color is not None:
                break
        if fill_color is None:
            continue

        # Fill the interior between left and right blue walls for rows above the bottom wall
        for r in range(rmin + 1, rmax):
            left = None
            right = None
            for c in range(cmin, cmax + 1):
                if grid[r, c] == 1:
                    if left is None:
                        left = c
                    right = c
            if left is not None and right is not None and right > left:
                for c in range(left + 1, right):
                    if out[r, c] == 0:
                        out[r, c] = fill_color

        # Fill the opening in the top blue row
        top_row = rmin
        left = None
        right = None
        for c in range(cmin, cmax + 1):
            if grid[top_row, c] == 1:
                if left is None:
                    left = c
                right = c
        if left is not None and right is not None and right > left:
            for c in range(left + 1, right):
                if out[top_row, c] == 0:
                    out[top_row, c] = fill_color

        # Draw a horizontal line one row above the container spanning full width
        line_row = rmin - 1
        if line_row >= 0:
            for c in range(cmin, cmax + 1):
                if out[line_row, c] == 0:
                    out[line_row, c] = fill_color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    bg = 0
    obj = 5
    fill = 2

    visited = np.zeros((h, w), dtype=bool)

    for r in range(h):
        for c in range(w):
            if grid[r, c] != bg or visited[r, c]:
                continue

            stack = [(r, c)]
            visited[r, c] = True
            comp = []
            touches_border = False

            while stack:
                x, y = stack.pop()
                comp.append((x, y))
                if x == 0 or x == h - 1 or y == 0 or y == w - 1:
                    touches_border = True
                for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == bg:
                        visited[nx, ny] = True
                        stack.append((nx, ny))

            if not touches_border:
                size = len(comp)
                root = int(np.sqrt(size))
                if root * root == size:
                    for x, y in comp:
                        grid[x, y] = fill

    return grid

