import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.asarray(input_grid)
    seen = set()
    colors = []
    for x in grid.ravel():
        v = int(x)
        if v != 0 and v not in seen:
            seen.add(v)
            colors.append(v)
    if grid.shape[1] > grid.shape[0]:
        return np.array([colors], dtype=int)
    return np.array(colors, dtype=int).reshape(-1, 1)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the 3x3 X-shaped object: center plus four diagonals, all same nonzero color.
    center = None
    color = None
    for r in range(1, h - 1):
        for c in range(1, w - 1):
            v = grid[r, c]
            if v == 0:
                continue
            if (grid[r - 1, c - 1] == v and grid[r - 1, c + 1] == v and
                grid[r + 1, c - 1] == v and grid[r + 1, c + 1] == v):
                center = (r, c)
                color = v
                break
        if center is not None:
            break

    if center is None:
        return grid

    cr, cc = center

    # Collect all cells of the other object(s): nonzero cells not part of the X.
    x_cells = {
        (cr, cc),
        (cr - 1, cc - 1), (cr - 1, cc + 1),
        (cr + 1, cc - 1), (cr + 1, cc + 1)
    }

    src = []
    for r in range(h):
        for c in range(w):
            if grid[r, c] != 0 and (r, c) not in x_cells:
                src.append((r, c, grid[r, c]))

    # Mirror each source cell across both axes through the X center.
    for r, c, v in src:
        dr = r - cr
        dc = c - cc
        for rr in (cr + dr, cr - dr):
            for cc2 in (cc + dc, cc - dc):
                if 0 <= rr < h and 0 <= cc2 < w:
                    grid[rr, cc2] = v

    return grid

