import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    coords = np.argwhere(grid != 0)
    if coords.size == 0:
        return grid
    color = int(grid[coords[0][0], coords[0][1]])
    if len(coords) == 1:
        return grid
    rows = coords[:, 0]
    cols = coords[:, 1]
    cr = int(np.median(rows))
    cc = int(np.median(cols))
    if len(coords) >= 2:
        d = int(np.min(np.abs(rows - cr)[np.abs(rows - cr) > 0])) if np.any(np.abs(rows - cr) > 0) else 1
        if d == 0:
            diffs = np.abs(np.diff(np.sort(rows)))
            diffs = diffs[diffs > 0]
            d = int(diffs[0]) if diffs.size else 1
    else:
        d = 1
    h, w = grid.shape
    out = np.zeros((h, w), dtype=grid.dtype)
    for r in range(h):
        for c in range(w):
            m = max(abs(r - cr), abs(c - cc))
            if m == 0 or (m > 0 and m % d == 0):
                out[r, c] = color
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    rows = []
    for i in range(h):
        nz = g[i][g[i] != 0]
        if len(nz) == w:
            rows.append(i)
    cols = []
    for j in range(w):
        nz = g[:, j][g[:, j] != 0]
        if len(nz) == h:
            cols.append(j)

    top, bottom = rows[0], rows[-1]
    left, right = cols[0], cols[-1]

    out = np.zeros((bottom - top + 1, right - left + 1), dtype=int)

    # borders
    out[0, :] = g[top, left:right + 1]
    out[-1, :] = g[bottom, left:right + 1]
    out[:, 0] = g[top:bottom + 1, left]
    out[:, -1] = g[top:bottom + 1, right]

    # interior markers that match a border color
    border_colors = {g[top, left], g[top, right], g[bottom, left], g[bottom, right]}
    interior = g[top + 1:bottom, left + 1:right]

    for r in range(interior.shape[0]):
        for c in range(interior.shape[1]):
            color = interior[r, c]
            if color == 0 or color not in border_colors:
                continue

            rr, cc = r + 1, c + 1
            if color == g[top, left]:
                for x in range(rr, 0, -1):
                    out[x, cc] = color
            elif color == g[top, right]:
                for x in range(rr, 0, -1):
                    out[x, cc] = color
            elif color == g[bottom, left]:
                for x in range(rr, out.shape[0] - 1):
                    out[x, cc] = color
            elif color == g[bottom, right]:
                for x in range(rr, out.shape[0] - 1):
                    out[x, cc] = color

    return out

