def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    out = grid.copy()
    color = 4
    rows, cols = np.where(grid == color)
    if len(rows) == 0:
        return out

    # Find connected components of the target color
    visited = np.zeros(grid.shape, dtype=bool)
    h, w = grid.shape
    dirs = [(1,0), (-1,0), (0,1), (0,-1)]

    for r0, c0 in zip(rows, cols):
        if visited[r0, c0]:
            continue
        stack = [(r0, c0)]
        comp = []
        visited[r0, c0] = True
        while stack:
            r, c = stack.pop()
            comp.append((r, c))
            for dr, dc in dirs:
                nr, nc = r + dr, c + dc
                if 0 <= nr < h and 0 <= nc < w and not visited[nr, nc] and grid[nr, nc] == color:
                    visited[nr, nc] = True
                    stack.append((nr, nc))

        comp_rows = {r for r, _ in comp}
        comp_cols = {c for _, c in comp}
        for r in comp_rows:
            for c in comp_cols:
                if out[r, c] == 0:
                    out[r, c] = 7

    return out

