def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    bg = 0
    grey = 5

    visited = np.zeros((h, w), dtype=bool)
    comps = []

    for r in range(h):
        for c in range(w):
            if grid[r, c] != bg and grid[r, c] != grey and not visited[r, c]:
                color = grid[r, c]
                stack = [(r, c)]
                visited[r, c] = True
                cells = []
                while stack:
                    x, y = stack.pop()
                    cells.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == color:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                rs = [p[0] for p in cells]
                cs = [p[1] for p in cells]
                minr, minc = min(rs), min(cs)
                norm = tuple(sorted((x - minr, y - minc) for x, y in cells))
                comps.append({
                    "color": color,
                    "cells": cells,
                    "norm": norm,
                    "pos": (minr, minc),
                    "order": len(comps)
                })

    seen = {}
    to_recolor = None
    for comp in comps:
        key = comp["norm"]
        if key in seen:
            to_recolor = comp
            break
        seen[key] = comp

    if to_recolor is not None:
        for x, y in to_recolor["cells"]:
            grid[x, y] = grey

    return grid

