def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    for i in range(h - 2):
        for j in range(w - 2):
            if np.all(g[i:i+3, j:j+3] == 0):
                if not (i > 0 and j > 0 and np.all(g[i-1:i+2, j-1:j+2] == 0)):
                    g[i:i+3, j:j+3] = 1
    return g

