def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    colors = [c for c in np.unique(grid) if c != 0]
    n = len(colors)
    out = np.zeros((3, 3), dtype=int)
    if n == 1:
        out[0, :] = 5
    elif n == 2:
        np.fill_diagonal(out, 5)
    elif n == 3:
        for i in range(3):
            out[i, 2 - i] = 5
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    out = g.copy()

    directions = [
        (0, 1),   # horizontal
        (1, 0),   # vertical
        (1, 1),   # diagonal down-right
        (1, -1),  # diagonal down-left
    ]

    learned = set()

    # Learn all complete A-B-A triples
    for r in range(h):
        for c in range(w):
            b = g[r, c]
            if b == 0:
                continue
            for dr, dc in directions:
                r1, c1 = r - dr, c - dc
                r2, c2 = r + dr, c + dc
                if 0 <= r1 < h and 0 <= c1 < w and 0 <= r2 < h and 0 <= c2 < w:
                    a1 = g[r1, c1]
                    a2 = g[r2, c2]
                    if a1 != 0 and a1 == a2 and a1 != b:
                        learned.add((a1, b, dr, dc))

    # Complete all matching incomplete triples for each learned pattern
    for a, b, dr, dc in learned:
        for r in range(h):
            for c in range(w):
                # center present alone -> add outers
                if g[r, c] == b:
                    r1, c1 = r - dr, c - dc
                    r2, c2 = r + dr, c + dc
                    if 0 <= r1 < h and 0 <= c1 < w and g[r1, c1] == 0:
                        out[r1, c1] = a
                    if 0 <= r2 < h and 0 <= c2 < w and g[r2, c2] == 0:
                        out[r2, c2] = a

                # two outers present with center missing -> add center
                r1, c1 = r - dr, c - dc
                r2, c2 = r + dr, c + dc
                if 0 <= r1 < h and 0 <= c1 < w and 0 <= r2 < h and 0 <= c2 < w:
                    if g[r1, c1] == a and g[r2, c2] == a and g[r, c] == 0:
                        out[r, c] = b

                # one side missing -> add missing outer if center and one outer present
                if g[r, c] == a:
                    # treat current cell as one outer; infer center and other outer
                    rc, cc = r + dr, c + dc
                    rb, cb = r + 2 * dr, c + 2 * dc
                    if 0 <= rc < h and 0 <= cc < w and 0 <= rb < h and 0 <= cb < w:
                        if g[rc, cc] == b and g[rb, cb] == 0:
                            out[rb, cb] = a
                    rc, cc = r - dr, c - dc
                    rb, cb = r - 2 * dr, c - 2 * dc
                    if 0 <= rc < h and 0 <= cc < w and 0 <= rb < h and 0 <= cb < w:
                        if g[rc, cc] == b and g[rb, cb] == 0:
                            out[rb, cb] = a

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    n, m = g.shape
    assert n == m
    out = g.copy()

    # First pass: fill black cells from their transposed counterparts when available.
    for i in range(n):
        for j in range(m):
            if out[i, j] == 0:
                t = out[j, i]
                if t != 0:
                    out[i, j] = t

    # Determine the cyclic palette from non-black values present.
    vals = [int(x) for x in np.unique(g) if x != 0]
    vals = sorted(vals)
    if not vals:
        return out

    # Background color is the palette color immediately preceding the diagonal color.
    # The diagonal color is the color appearing on the main diagonal in the completed table.
    # Infer it as the most frequent non-black diagonal value if present, else the first palette value.
    diag_vals = [int(out[i, i]) for i in range(n) if out[i, i] != 0]
    if diag_vals:
        diag_color = max(set(diag_vals), key=diag_vals.count)
    else:
        diag_color = vals[0]

    if diag_color in vals:
        idx = vals.index(diag_color)
        bg_color = vals[idx - 1] if idx > 0 else vals[-1]
    else:
        bg_color = vals[-1]

    # Second pass: fill any remaining black cells.
    for i in range(n):
        for j in range(m):
            if out[i, j] == 0:
                if i == j:
                    out[i, j] = diag_color
                else:
                    out[i, j] = bg_color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    rows = np.where(np.all(g == 0, axis=1))[0]
    cols = np.where(np.all(g == 0, axis=0))[0]

    r_bounds = [-1] + rows.tolist() + [g.shape[0]]
    c_bounds = [-1] + cols.tolist() + [g.shape[1]]

    out = []
    for i in range(len(r_bounds) - 1):
        r0, r1 = r_bounds[i] + 1, r_bounds[i + 1]
        if r0 >= r1:
            continue
        row_vals = []
        for j in range(len(c_bounds) - 1):
            c0, c1 = c_bounds[j] + 1, c_bounds[j + 1]
            if c0 >= c1:
                continue
            panel = g[r0:r1, c0:c1]
            nz = panel[panel != 0]
            row_vals.append(int(nz[0]) if nz.size else 0)
        if row_vals:
            out.append(row_vals)

    return np.array(out, dtype=int)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    wall = g != 0
    visited = np.zeros((h, w), dtype=bool)
    stack = []

    def push(r, c):
        if 0 <= r < h and 0 <= c < w and not wall[r, c] and not visited[r, c]:
            visited[r, c] = True
            stack.append((r, c))

    for c in range(w):
        push(0, c)
        push(h - 1, c)
    for r in range(h):
        push(r, 0)
        push(r, w - 1)

    while stack:
        r, c = stack.pop()
        if r > 0:
            push(r - 1, c)
        if r + 1 < h:
            push(r + 1, c)
        if c > 0:
            push(r, c - 1)
        if c + 1 < w:
            push(r, c + 1)

    out = np.where(wall, g, np.where(visited, 3, 2))
    return out

