def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = grid.copy()
    grey = 5

    for r in range(h - 1):
        for c in range(w - 1):
            if grid[r, c] == grey and grid[r, c + 1] == grey and grid[r + 1, c] == grey and grid[r + 1, c + 1] == grey:
                if r - 1 >= 0 and c - 1 >= 0:
                    out[r - 1, c - 1] = 1
                if r - 1 >= 0 and c + 2 < w:
                    out[r - 1, c + 2] = 2
                if r + 2 < h and c - 1 >= 0:
                    out[r + 2, c - 1] = 3
                if r + 2 < h and c + 2 < w:
                    out[r + 2, c + 2] = 4
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = input_grid
    h, w = g.shape
    bg = 2

    # Find bounding box of the red canvas (cells that are not background outside)
    non_bg = np.argwhere(g != 0)
    if non_bg.size == 0:
        return g.copy()
    r0, c0 = non_bg.min(axis=0)
    r1, c1 = non_bg.max(axis=0) + 1
    canvas = g[r0:r1, c0:c1].copy()

    # Find all 3x3 clue masks outside the canvas: one non-bg color plus red cells
    clues = []
    visited = np.zeros_like(g, dtype=bool)

    for r in range(h - 2):
        for c in range(w - 2):
            block = g[r:r+3, c:c+3]
            vals = block[block != 0]
            if vals.size == 0:
                continue
            uniq = np.unique(vals)
            if len(uniq) != 2 or bg not in uniq:
                continue
            other = uniq[uniq != bg][0]
            red_mask = (block == bg)
            if red_mask.sum() == 0:
                continue
            clues.append((other, red_mask.astype(np.uint8)))

    def rotations(mask):
        ms = []
        m = mask
        for _ in range(4):
            ms.append(m)
            m = np.rot90(m)
        return ms

    # Collect canvas cutouts: 3x3 regions with zeros inside the red canvas
    cutouts = []
    for r in range(canvas.shape[0] - 2):
        for c in range(canvas.shape[1] - 2):
            block = canvas[r:r+3, c:c+3]
            if np.any(block == 0):
                cutouts.append((r, c, (block == 0).astype(np.uint8)))

    # Match each cutout to a clue by rotated red pattern
    used = set()
    for r, c, hole_mask in cutouts:
        matched_color = None
        for idx, (color, red_mask) in enumerate(clues):
            if idx in used:
                continue
            for rm in rotations(red_mask):
                if np.array_equal(rm, hole_mask):
                    matched_color = color
                    used.add(idx)
                    break
            if matched_color is not None:
                break
        if matched_color is None:
            continue
        block = canvas[r:r+3, c:c+3]
        block[block == 0] = matched_color
        canvas[r:r+3, c:c+3] = block

    return canvas

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    sep_rows = np.where(np.all(grid == 4, axis=1))[0]
    if len(sep_rows) == 0:
        return grid.copy()
    sep = sep_rows[0]
    upper = grid[:sep]
    lower = grid[sep + 1:]
    upper = (upper == 1).astype(int)
    lower = (lower == 2).astype(int)
    out = (upper + lower) % 2
    return (out * 3).astype(int)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    H, W = g.shape
    color = int(np.max(g[g != 0])) if np.any(g != 0) else 0

    # Find connected non-zero components (4-neighborhood)
    visited = np.zeros((H, W), dtype=bool)
    comps = []

    for r in range(H):
        for c in range(W):
            if g[r, c] == 0 or visited[r, c]:
                continue
            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < H and 0 <= ny < W and not visited[nx, ny] and g[nx, ny] != 0:
                        visited[nx, ny] = True
                        stack.append((nx, ny))
            comps.append(cells)

    out = np.zeros_like(g)

    for cells in comps:
        vals = [g[r, c] for r, c in cells]
        main_color = max(set(vals), key=vals.count)
        # bounding box of the component
        rs = [r for r, c in cells]
        cs = [c for r, c in cells]
        r0, r1 = min(rs), max(rs)
        c0, c1 = min(cs), max(cs)

        # identify the unique non-main-color cell (the red marker)
        marker = None
        for r, c in cells:
            if g[r, c] != main_color:
                marker = (r, c)
                break
        if marker is None:
            # no marker; just copy component
            for r, c in cells:
                out[r, c] = g[r, c]
            continue

        mr, mc = marker

        # Determine which side of the rectangle the marker lies on
        dist_top = mr - r0
        dist_bottom = r1 - mr
        dist_left = mc - c0
        dist_right = c1 - mc

        # Rectangle dimensions
        height = r1 - r0 + 1
        width = c1 - c0 + 1

        # Beam direction and thickness
        if dist_top == 0:
            # marker on top side -> beam upward
            radius = dist_bottom
            for rr in range(0, r0):
                for cc in range(max(0, mc - radius), min(W - 1, mc + radius) + 1):
                    out[rr, cc] = main_color
            for rr in range(0, r0):
                out[rr, mc] = g[mr, mc]
        elif dist_bottom == 0:
            # marker on bottom side -> beam downward
            radius = dist_top
            for rr in range(r1 + 1, H):
                for cc in range(max(0, mc - radius), min(W - 1, mc + radius) + 1):
                    out[rr, cc] = main_color
            for rr in range(r1 + 1, H):
                out[rr, mc] = g[mr, mc]
        elif dist_left == 0:
            # marker on left side -> beam leftward
            radius = dist_right
            for cc in range(0, c0):
                for rr in range(max(0, mr - radius), min(H - 1, mr + radius) + 1):
                    out[rr, cc] = main_color
            for cc in range(0, c0):
                out[mr, cc] = g[mr, mc]
        elif dist_right == 0:
            # marker on right side -> beam rightward
            radius = dist_left
            for cc in range(c1 + 1, W):
                for rr in range(max(0, mr - radius), min(H - 1, mr + radius) + 1):
                    out[rr, cc] = main_color
            for cc in range(c1 + 1, W):
                out[mr, cc] = g[mr, mc]

        # Copy original component unchanged
        for r, c in cells:
            out[r, c] = g[r, c]

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = input_grid
    h, w = g.shape
    out = np.zeros((h, w), dtype=int)
    grey = (g == 5)

    for r in range(h):
        for c in range(w):
            if not grey[r, c]:
                continue
            n = 0
            if r > 0 and grey[r - 1, c]:
                n += 1
            if r + 1 < h and grey[r + 1, c]:
                n += 1
            if c > 0 and grey[r, c - 1]:
                n += 1
            if c + 1 < w and grey[r, c + 1]:
                n += 1

            if n == 2:
                out[r, c] = 1
            elif n == 3:
                out[r, c] = 4
            elif n == 4:
                out[r, c] = 2
            else:
                out[r, c] = 5
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    teal = 8

    # Find all non-teal connected components (4-connected)
    visited = np.zeros((h, w), dtype=bool)
    components = []

    for r in range(h):
        for c in range(w):
            if grid[r, c] != teal and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                comp = []
                while stack:
                    x, y = stack.pop()
                    comp.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < h and 0 <= ny < w and grid[nx, ny] != teal and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                components.append(comp)

    # Identify the component containing pre-colored cells (non-zero, non-teal)
    target_comp = None
    clue_colors = set()
    for comp in components:
        colored = [(r, c) for r, c in comp if grid[r, c] != 0]
        if colored:
            target_comp = comp
            clue_colors = {grid[r, c] for r, c in colored}
            break

    if target_comp is None:
        return grid

    # Determine parity-to-color mapping from clue cells
    parity_to_color = {}
    for r, c in target_comp:
        val = grid[r, c]
        if val != 0:
            parity_to_color[(r + c) % 2] = val

    # Fill black cells in target component according to parity
    for r, c in target_comp:
        if grid[r, c] == 0:
            parity = (r + c) % 2
            if parity in parity_to_color:
                grid[r, c] = parity_to_color[parity]

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = input_grid.copy()
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    def flood_fill(sr, sc):
        stack = [(sr, sc)]
        cells = []
        touches_border = False
        while stack:
            r, c = stack.pop()
            if r < 0 or r >= h or c < 0 or c >= w:
                continue
            if visited[r, c] or grid[r, c] != 0:
                continue
            visited[r, c] = True
            cells.append((r, c))
            if r == 0 or r == h - 1 or c == 0 or c == w - 1:
                touches_border = True
            stack.extend([(r - 1, c), (r + 1, c), (r, c - 1), (r, c + 1)])
        return cells, touches_border

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 0 and not visited[r, c]:
                cells, touches_border = flood_fill(r, c)
                if not touches_border and cells:
                    n = len(cells)
                    fill_color = {1: 6, 4: 7, 9: 8}.get(n, None)
                    if fill_color is not None:
                        for rr, cc in cells:
                            grid[rr, cc] = fill_color
    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    vals, counts = np.unique(grid, return_counts=True)
    nonzero = vals[vals != 0]
    if nonzero.size == 0:
        return grid.copy()
    rare_color = nonzero[np.argmin(counts[vals != 0])]
    coords = np.argwhere(grid == rare_color)
    r0, c0 = coords.min(axis=0)
    r1, c1 = coords.max(axis=0)
    return grid[r0:r1 + 1, c0:c1 + 1].copy()

