import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    vals, counts = np.unique(grid, return_counts=True)
    bg_colors = set(vals[counts > 1].tolist())
    marker_positions = [(r, c, grid[r, c]) for r in range(h) for c in range(w) if grid[r, c] not in bg_colors]

    # Map each background color to the rare marker color found inside it
    bg_to_marker = {}
    for r, c, color in marker_positions:
        bg = None
        # Determine surrounding background color by looking at the most common color in row/col neighborhood is not reliable.
        # Instead, infer from the color occupying the cell's connected region of same background color after removing rare markers.
        # Since backgrounds are large and only rare markers differ, the original background at the marker cell is the dominant color
        # in its row/column block. We can infer it by checking the most frequent color among its 4-neighbors and itself among bg colors.
        candidates = []
        for rr, cc in ((r-1,c), (r+1,c), (r,c-1), (r,c+1), (r,c)):
            if 0 <= rr < h and 0 <= cc < w and grid[rr, cc] in bg_colors:
                candidates.append(grid[rr, cc])
        if candidates:
            bg = max(set(candidates), key=candidates.count)
            bg_to_marker[bg] = color

    out = grid.copy()

    for r, c, color in marker_positions:
        # Draw diagonals through the marker
        for rr in range(h):
            cc = c + (rr - r)
            if 0 <= cc < w and out[rr, cc] in bg_to_marker:
                out[rr, cc] = bg_to_marker[out[rr, cc]]
            cc = c - (rr - r)
            if 0 <= cc < w and out[rr, cc] in bg_to_marker:
                out[rr, cc] = bg_to_marker[out[rr, cc]]

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape
    corners = []
    for r in range(h):
        for c in range(w):
            v = int(g[r, c])
            if v != 0:
                corners.append((r, c, v))
    out = np.zeros((h, w), dtype=int)
    if not corners:
        return out

    for r in range(h):
        for c in range(w):
            dists = []
            for cr, cc, col in corners:
                d = (r - cr) * (r - cr) + (c - cc) * (c - cc)
                dists.append((d, cr, cc, col))
            dists.sort(key=lambda x: x[0])
            if len(dists) >= 2 and dists[0][0] == dists[1][0]:
                continue
            d, cr, cc, col = dists[0]
            side = max(abs(r - cr), abs(c - cc)) + 1
            if side % 2 == 1:
                out[r, c] = col
    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the 2x2 green square (color 3)
    green = 3
    pos = np.argwhere(grid == green)
    if pos.size == 0:
        return grid

    # Determine bounding box of the green square
    r0, c0 = pos.min(axis=0)
    r1, c1 = pos.max(axis=0)

    # Keep original grid and extend non-green pixels aligned with the square
    for r in range(h):
        for c in range(w):
            color = grid[r, c]
            if color == 0 or color == green:
                continue

            # Same row as any cell of the green square
            if r0 <= r <= r1:
                if c < c0:
                    grid[r, c + 1:c0] = color
                elif c > c1:
                    grid[r, c1 + 1:c] = color

            # Same column as any cell of the green square
            elif c0 <= c <= c1:
                if r < r0:
                    grid[r + 1:r0, c] = color
                elif r > r1:
                    grid[r1 + 1:r, c] = color

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    markers = []
    for c in range(w):
        v = grid[0, c]
        if v != 0:
            markers.append((c, int(v)))
    markers.sort(key=lambda x: x[0])

    visited = np.zeros((h, w), dtype=bool)
    components = []

    for r in range(h):
        for c in range(w):
            if grid[r, c] == 5 and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                cells = []
                while stack:
                    x, y = stack.pop()
                    cells.append((x, y))
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < h and 0 <= ny < w and not visited[nx, ny] and grid[nx, ny] == 5:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                cols = [y for _, y in cells]
                center = (min(cols) + max(cols)) / 2.0
                components.append((center, cells))

    components.sort(key=lambda x: x[0])

    for (_, color), (_, cells) in zip(markers, components):
        for r, c in cells:
            grid[r, c] = color

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    visited = np.zeros((h, w), dtype=bool)

    def neighbors(r, c):
        if r > 0:
            yield r - 1, c
        if r + 1 < h:
            yield r + 1, c
        if c > 0:
            yield r, c - 1
        if c + 1 < w:
            yield r, c + 1

    for r in range(h):
        for c in range(w):
            if grid[r, c] != 0 or visited[r, c]:
                continue

            stack = [(r, c)]
            visited[r, c] = True
            component = []
            touches_top = False
            touches_bottom = False
            touches_left = False
            touches_right = False

            while stack:
                cr, cc = stack.pop()
                component.append((cr, cc))
                if cr == 0:
                    touches_top = True
                if cr == h - 1:
                    touches_bottom = True
                if cc == 0:
                    touches_left = True
                if cc == w - 1:
                    touches_right = True

                for nr, nc in neighbors(cr, cc):
                    if grid[nr, nc] == 0 and not visited[nr, nc]:
                        visited[nr, nc] = True
                        stack.append((nr, nc))

            if touches_top or touches_bottom:
                continue

            if touches_left and touches_right:
                continue

            for cr, cc in component:
                grid[cr, cc] = 4

    return grid

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.full((h, w), 5, dtype=int)

    visited = np.zeros((h, w), dtype=bool)
    dirs = [(-1, 0), (1, 0), (0, -1), (0, 1)]

    for r in range(h):
        for c in range(w):
            if grid[r, c] != 0 or visited[r, c]:
                continue

            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            perimeter = 0

            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if nx < 0 or nx >= h or ny < 0 or ny >= w or grid[nx, ny] != 0:
                        perimeter += 1
                    elif not visited[nx, ny]:
                        visited[nx, ny] = True
                        stack.append((nx, ny))

            color = {4: 3, 6: 2, 8: 1}.get(perimeter, 5)
            for x, y in cells:
                out[x, y] = color

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    return np.rot90(input_grid, k=1)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    ys, xs = np.where(grid != 0)
    if len(ys) == 0:
        return np.zeros((0, 0), dtype=grid.dtype)
    y0, y1 = ys.min(), ys.max()
    x0, x1 = xs.min(), xs.max()
    crop = grid[y0:y1 + 1, x0:x1 + 1]
    return np.repeat(np.repeat(crop, 2, axis=0), 2, axis=1)

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    colors = np.unique(grid)
    other = colors[colors != 5]
    if other.size == 0:
        return np.zeros_like(grid)
    c = other[0]
    out = np.where(grid == 5, c, 0)
    return out
